function addMenuExtendedPreviewMode(plugin, menu, fileBaseName, currentMd) {
  const file = plugin.app.vault.getAbstractFileByPath(
    plugin.app.metadataCache.getFirstLinkpathDest(fileBaseName, currentMd.path)?.path ?? fileBaseName
  );
  if (!(file instanceof obsidian.TFile)) {
    return;
  }
  menu.addItem(
    (item) => item.setIcon("copy").setTitle(isChineseDisplayLanguage() ? "\u590D\u5236\u56FE\u7247\u5230\u526A\u8D34\u677F" : "Copy Image to Clipboard").onClick(async () => {
      try {
        const sourceMimeType = getImageMimeTypeFromExtension(file.extension);
        const sourceBlob = new Blob([await file.vault.readBinary(file)], {
          type: sourceMimeType
        });
        const { blob, mimeType, convertedToPng } = await normalizeImageBlobForClipboard(
          sourceBlob,
          sourceMimeType
        );
        await navigator.clipboard.write([new ClipboardItem({ [mimeType]: blob })]);
        new obsidian.Notice(convertedToPng ? isChineseDisplayLanguage() ? "\u5DF2\u590D\u5236\u5230\u526A\u8D34\u677F\uFF08\u5DF2\u81EA\u52A8\u8F6C\u6362\u4E3A PNG\uFF09" : "Copied to clipboard (automatically converted to PNG)" : isChineseDisplayLanguage() ? "\u5DF2\u590D\u5236\u5230\u526A\u8D34\u677F" : "Copied to clipboard");
      } catch (error) {
        console.error("Failed to copy image:", error);
        new obsidian.Notice(isChineseDisplayLanguage() ? "\u590D\u5236\u6587\u4EF6\u5931\u8D25\uFF01" : "Failed to copy file!");
      }
    })
  );
  menu.addItem(
    (item) => item.setIcon("arrow-up-right").setTitle(isChineseDisplayLanguage() ? "\u4F7F\u7528\u9ED8\u8BA4\u5E94\u7528\u6253\u5F00" : "Open with Default App").onClick(() => {
      const appWithDesktopApi = plugin.app;
      appWithDesktopApi.openWithDefaultApp(file.path);
    })
  );
  menu.addItem(
    (item) => item.setIcon("arrow-up-right").setTitle(obsidian.Platform.isMacOS ? isChineseDisplayLanguage() ? "\u5728 Finder \u4E2D\u663E\u793A" : "Show in Finder" : isChineseDisplayLanguage() ? "\u5728\u7CFB\u7EDF\u8D44\u6E90\u7BA1\u7406\u5668\u4E2D\u663E\u793A" : "Show in File Explorer").onClick(() => {
      const appWithDesktopApi = plugin.app;
      appWithDesktopApi.showInFolder(file.path);
    })
  );
  menu.addItem(
    (item) => item.setIcon("folder").setTitle(isChineseDisplayLanguage() ? "\u5728\u5BFC\u822A\u4E2D\u5B9A\u4F4D\u6587\u4EF6" : "Locate in Navigation").onClick(() => {
      plugin.previewFeature?.locateFileInExplorer(file);
    })
  );
}
